 15→/**
 16→ * Intake page — role profile intake UI with all states: Input, Loading, Preview, Confirmed, Error.
 17→ * Supports re-intake (Update Profile) from the Confirmed state.
 18→ * FR-003: Employees can generate and confirm a role profile for their tenant.
 19→ * Constitution VI: All user-facing strings are centralised in STRINGS for i18n readiness.
 20→ */
 21→
 22→"use client";
 23→
 24→import { use, useEffect, useState } from "react";
 25→
 26→// ---------------------------------------------------------------------------
 27→// String catalog — Constitution VI i18n requirement
 28→// ---------------------------------------------------------------------------
 29→
 30→const STRINGS = {
 31→  pageTitle: "Role Profile Intake",
 32→  inputLabel: "Job Description",
 33→  inputPlaceholder: "Paste your job description here (minimum 50 characters)...",
 34→  charCounter: (current: number, max: number) => `${current} / ${max} characters`,
 35→  generateButton: "Generate Profile",
 36→  generatingMessage: "Analyzing your job description...",
 37→  previewTitle: "Your Role Profile",
 38→  previewSubtitle: "Review and edit your job expectations below:",
 39→  expectationLabel: (index: number) => `Job expectation ${index + 1}`,
 40→  addExpectation: "Add Expectation",
 41→  removeExpectation: "Remove",
 42→  confirmButton: "Confirm Profile",
 43→  startOverButton: "Start Over",
 44→  confirmedTitle: "Profile Saved",
 45→  confirmedMessage: "Your role profile has been saved.",
 46→  dashboardLink: "Go to Dashboard",
 47→  errorTitle: "Something went wrong",
 48→  retryButton: "Retry",
 49→  updateProfileButton: "Update Profile",
 50→  reintakeBanner: "Your current profile will remain active until you confirm the new one.",
 51→  currentProfileTitle: "Current Profile",
 52→  newPreviewTitle: "New Profile Preview",
 53→  minExpectations: "At least 1 job expectation is required",
 54→  maxExpectations: "Maximum 15 job expectations allowed",
 55→  minChars: "Minimum 50 characters required",
 56→  maxChars: "Maximum 10,000 characters allowed",
 57→} as const;
 58→
 59→// ---------------------------------------------------------------------------
 60→// Constants
 61→// ---------------------------------------------------------------------------
 62→
 63→const MAX_CHARS = 10_000;
 64→const MIN_CHARS = 50;
 65→const MAX_EXPECTATIONS = 15;
 66→
 67→// ---------------------------------------------------------------------------
 68→// Types
 69→// ---------------------------------------------------------------------------
 70→
 71→type IntakeState = "loading-profile" | "input" | "loading" | "preview" | "confirmed" | "error";
 72→
 73→interface RoleProfile {
 74→  id: string;
 75→  jobExpectations: string[];
 76→  version: number;
 77→  confirmedAt: string;
 78→}
 79→
 80→// ---------------------------------------------------------------------------
 81→// Shared inline style objects
 82→// ---------------------------------------------------------------------------
 83→
 84→const containerStyle: React.CSSProperties = {
 85→  maxWidth: "800px",
 86→  margin: "2rem auto",
 87→  padding: "0 1rem",
 88→  fontFamily: "system-ui, sans-serif",
 89→};
 90→
 91→const headingStyle: React.CSSProperties = {
 92→  fontSize: "1.5rem",
 93→  fontWeight: 600,
 94→  marginBottom: "0.5rem",
 95→  color: "#111",
 96→};
 97→
 98→const labelStyle: React.CSSProperties = {
 99→  display: "block",
100→  fontWeight: 500,
101→  marginBottom: "0.5rem",
102→  color: "#111",
103→};
104→
105→const textareaStyle: React.CSSProperties = {
106→  width: "100%",
107→  minHeight: "180px",
108→  padding: "0.75rem",
109→  border: "1px solid #ccc",
110→  borderRadius: "4px",
111→  fontSize: "0.95rem",
112→  fontFamily: "system-ui, sans-serif",
113→  resize: "vertical",
114→  boxSizing: "border-box",
115→};
116→
117→const primaryButtonStyle: React.CSSProperties = {
118→  padding: "0.65rem 1.5rem",
119→  backgroundColor: "#1a73e8",
120→  color: "white",
121→  border: "none",
122→  borderRadius: "4px",
123→  fontSize: "0.95rem",
124→  fontWeight: 500,
125→  cursor: "pointer",
126→};
127→
128→const secondaryButtonStyle: React.CSSProperties = {
129→  padding: "0.65rem 1.5rem",
130→  backgroundColor: "#f5f5f5",
131→  color: "#111",
132→  border: "1px solid #ddd",
133→  borderRadius: "4px",
134→  fontSize: "0.95rem",
135→  fontWeight: 500,
136→  cursor: "pointer",
137→};
138→
139→const dangerButtonStyle: React.CSSProperties = {
140→  padding: "0.35rem 0.75rem",
141→  backgroundColor: "#fff",
142→  color: "#b91c1c",
143→  border: "1px solid #b91c1c",
144→  borderRadius: "4px",
145→  fontSize: "0.875rem",
146→  cursor: "pointer",
147→};
148→
149→const validationMessageStyle: React.CSSProperties = {
150→  color: "#b91c1c",
151→  fontSize: "0.875rem",
152→  marginTop: "0.4rem",
153→};
154→
155→const hintStyle: React.CSSProperties = {
156→  color: "#555",
157→  fontSize: "0.875rem",
158→  marginTop: "0.4rem",
159→};
160→
161→const sectionCardStyle: React.CSSProperties = {
162→  border: "1px solid #e0e0e0",
163→  borderRadius: "6px",
164→  padding: "1.25rem",
165→  marginBottom: "1.5rem",
166→  backgroundColor: "#fafafa",
167→};
168→
169→const expectationInputStyle: React.CSSProperties = {
170→  flex: 1,
171→  padding: "0.5rem 0.75rem",
172→  border: "1px solid #ccc",
173→  borderRadius: "4px",
174→  fontSize: "0.9rem",
175→  fontFamily: "system-ui, sans-serif",
176→};
177→
178→const bannerStyle: React.CSSProperties = {
179→  padding: "0.75rem 1rem",
180→  backgroundColor: "#fff8e1",
181→  border: "1px solid #f9a825",
182→  borderRadius: "4px",
183→  marginBottom: "1.5rem",
184→  fontSize: "0.9rem",
185→  color: "#5f4c00",
186→};
187→
188→// ---------------------------------------------------------------------------
189→// Sub-components
190→// ---------------------------------------------------------------------------
191→
192→function LoadingSpinner() {
193→  return (
194→    <span
195→      aria-hidden="true"
196→      style={{
197→        display: "inline-block",
198→        width: "16px",
199→        height: "16px",
200→        border: "2px solid rgba(255,255,255,0.4)",
201→        borderTopColor: "white",
202→        borderRadius: "50%",
203→        animation: "spin 0.7s linear infinite",
204→        verticalAlign: "middle",
205→        marginRight: "0.5rem",
206→      }}
207→    />
208→  );
209→}
210→
211→// ---------------------------------------------------------------------------
212→// Main component
213→// ---------------------------------------------------------------------------
214→
215→export default function IntakePage({ params }: { params: Promise<{ tenant: string }> }) {
216→  const { tenant } = use(params);
217→
218→  const [intakeState, setIntakeState] = useState<IntakeState>("loading-profile");
219→  const [jobText, setJobText] = useState("");
220→  const [expectations, setExpectations] = useState<string[]>([""]);
221→  const [error, setError] = useState("");
222→  const [existingProfile, setExistingProfile] = useState<RoleProfile | null>(null);
223→  const [oldExpectations, setOldExpectations] = useState<string[]>([]);
224→
225→  // -------------------------------------------------------------------------
226→  // Derived validation
227→  // -------------------------------------------------------------------------
228→
229→  const charCount = jobText.length;
230→  const charCountValid = charCount >= MIN_CHARS && charCount <= MAX_CHARS;
231→  const charCountMessage =
232→    charCount < MIN_CHARS ? STRINGS.minChars : charCount > MAX_CHARS ? STRINGS.maxChars : null;
233→
234→  const expectationsValid =
235→    expectations.length >= 1 &&
236→    expectations.length <= MAX_EXPECTATIONS &&
237→    expectations.every((e) => e.trim().length > 0);
238→
239→  const expectationsCountMessage =
240→    expectations.length < 1
241→      ? STRINGS.minExpectations
242→      : expectations.length > MAX_EXPECTATIONS
243→        ? STRINGS.maxExpectations
244→        : null;
245→
246→  // -------------------------------------------------------------------------
247→  // On mount: fetch existing profile
248→  // -------------------------------------------------------------------------
249→
250→  useEffect(() => {
251→    let cancelled = false;
252→
253→    async function fetchProfile() {
254→      try {
255→        const res = await fetch(`/api/intake/${tenant}/profile`);
256→        if (cancelled) return;
257→
258→        if (res.ok) {
259→          const profile = (await res.json()) as RoleProfile;
260→          setExistingProfile(profile);
261→          setIntakeState("confirmed");
262→        } else if (res.status === 404) {
263→          setIntakeState("input");
264→        } else {
265→          setError(`Unexpected response (${res.status}). Please refresh and try again.`);
266→          setIntakeState("error");
267→        }
268→      } catch {
269→        if (!cancelled) {
270→          setError("Unable to load your profile. Please check your connection and try again.");
271→          setIntakeState("error");
272→        }
273→      }
274→    }
275→
276→    fetchProfile();
277→    return () => {
278→      cancelled = true;
279→    };
280→  }, [tenant]);
281→
282→  // -------------------------------------------------------------------------
283→  // Handlers
284→  // -------------------------------------------------------------------------
285→
286→  async function handleGenerate(e: React.FormEvent<HTMLFormElement>) {
287→    e.preventDefault();
288→    if (!charCountValid) return;
289→
290→    setIntakeState("loading");
291→    setError("");
292→
293→    try {
294→      const res = await fetch(`/api/intake/${tenant}/generate`, {
295→        method: "POST",
296→        headers: { "Content-Type": "application/json" },
297→        body: JSON.stringify({ jobText }),
298→      });
299→
300→      if (!res.ok) {
301→        const body = (await res.json().catch(() => ({}))) as { message?: string };
302→        throw new Error(body.message ?? `Server error (${res.status})`);
303→      }
304→
305→      const data = (await res.json()) as { jobExpectations: string[] };
306→      setExpectations(data.jobExpectations.length > 0 ? data.jobExpectations : [""]);
307→      setIntakeState("preview");
308→    } catch (err) {
309→      setError(
310→        err instanceof Error ? err.message : "Failed to generate profile. Please try again.",
311→      );
312→      setIntakeState("error");
313→    }
314→  }
315→
316→  async function handleConfirm(e: React.FormEvent<HTMLFormElement>) {
317→    e.preventDefault();
318→    if (!expectationsValid) return;
319→
320→    setIntakeState("loading");
321→    setError("");
322→
323→    try {
324→      const res = await fetch(`/api/intake/${tenant}/confirm`, {
325→        method: "POST",
326→        headers: { "Content-Type": "application/json" },
327→        body: JSON.stringify({ jobExpectations: expectations.map((e) => e.trim()) }),
328→      });
329→
330→      if (!res.ok) {
331→        const body = (await res.json().catch(() => ({}))) as { message?: string };
332→        throw new Error(body.message ?? `Server error (${res.status})`);
333→      }
334→
335→      const saved = (await res.json()) as RoleProfile;
336→      setExistingProfile(saved);
337→      setOldExpectations([]);
338→      setIntakeState("confirmed");
339→    } catch (err) {
340→      setError(err instanceof Error ? err.message : "Failed to save profile. Please try again.");
341→      setIntakeState("error");
342→    }
343→  }
344→
345→  function handleStartOver() {
346→    setJobText("");
347→    setExpectations([""]);
348→    setError("");
349→    setOldExpectations([]);
350→    setIntakeState("input");
351→  }
352→
353→  function handleUpdateProfile() {
354→    if (existingProfile) {
355→      setOldExpectations(existingProfile.jobExpectations);
356→    }
357→    setJobText("");
358→    setExpectations([""]);
359→    setError("");
360→    setIntakeState("input");
361→  }
362→
363→  function handleRetry() {
364→    setError("");
365→    setIntakeState(existingProfile ? "confirmed" : "input");
366→  }
367→
368→  // Expectation list helpers
369→  function handleExpectationChange(index: number, value: string) {
370→    setExpectations((prev) => prev.map((item, i) => (i === index ? value : item)));
371→  }
372→
373→  function handleAddExpectation() {
374→    if (expectations.length >= MAX_EXPECTATIONS) return;
375→    setExpectations((prev) => [...prev, ""]);
376→  }
377→
378→  function handleRemoveExpectation(index: number) {
379→    if (expectations.length <= 1) return;
380→    setExpectations((prev) => prev.filter((_, i) => i !== index));
381→  }
382→
383→  // -------------------------------------------------------------------------
384→  // Render helpers
385→  // -------------------------------------------------------------------------
386→
387→  function renderLoadingProfile() {
388→    return (
389→      <div aria-live="polite" aria-busy="true" style={{ padding: "2rem 0", textAlign: "center" }}>
390→        <p style={{ color: "#555" }}>Loading your profile...</p>
391→      </div>
392→    );
393→  }
394→
395→  function renderInput() {
396→    return (
397→      <>
398→        {oldExpectations.length > 0 && (
399→          <div role="note" style={bannerStyle}>
400→            {STRINGS.reintakeBanner}
401→          </div>
402→        )}
403→
404→        {oldExpectations.length > 0 && (
405→          <section
406→            aria-labelledby="current-profile-heading"
407→            style={{ ...sectionCardStyle, marginBottom: "2rem" }}
408→          >
409→            <h2
410→              id="current-profile-heading"
411→              style={{ fontSize: "1rem", fontWeight: 600, marginBottom: "0.75rem" }}
412→            >
413→              {STRINGS.currentProfileTitle}
414→            </h2>
415→            <ol style={{ margin: 0, paddingLeft: "1.25rem" }}>
416→              {oldExpectations.map((exp, i) => (
417→                <li
418→                  key={`${i}-${exp}`}
419→                  style={{ marginBottom: "0.4rem", fontSize: "0.9rem", color: "#333" }}
420→                >
421→                  {exp}
422→                </li>
423→              ))}
424→            </ol>
425→          </section>
426→        )}
427→
428→        <form onSubmit={handleGenerate} noValidate aria-labelledby="input-form-heading">
429→          <h1 id="input-form-heading" style={headingStyle}>
430→            {STRINGS.pageTitle}
431→          </h1>
432→
433→          <div style={{ marginBottom: "1.5rem" }}>
434→            <label htmlFor="job-description" style={labelStyle}>
435→              {STRINGS.inputLabel}
436→            </label>
437→            <textarea
438→              id="job-description"
439→              name="jobDescription"
440→              value={jobText}
441→              onChange={(e) => setJobText(e.target.value)}
442→              placeholder={STRINGS.inputPlaceholder}
443→              maxLength={MAX_CHARS}
444→              style={{
445→                ...textareaStyle,
446→                borderColor: charCount > 0 && charCountMessage ? "#b91c1c" : "#ccc",
447→              }}
448→              aria-describedby="char-count char-validation"
449→              aria-required="true"
450→              aria-invalid={charCount > 0 && charCountMessage !== null ? "true" : "false"}
451→            />
452→            <div id="char-count" style={hintStyle}>
453→              {STRINGS.charCounter(charCount, MAX_CHARS)}
454→            </div>
455→            {charCount > 0 && charCountMessage && (
456→              <div id="char-validation" role="alert" style={validationMessageStyle}>
457→                {charCountMessage}
458→              </div>
459→            )}
460→          </div>
461→
462→          <div style={{ display: "flex", gap: "0.75rem", flexWrap: "wrap" }}>
463→            <button
464→              type="submit"
465→              disabled={!charCountValid}
466→              style={{
467→                ...primaryButtonStyle,
468→                opacity: charCountValid ? 1 : 0.6,
469→                cursor: charCountValid ? "pointer" : "not-allowed",
470→              }}
471→            >
472→              {STRINGS.generateButton}
473→            </button>
474→
475→            {oldExpectations.length > 0 && (
476→              <button type="button" onClick={handleStartOver} style={secondaryButtonStyle}>
477→                {STRINGS.startOverButton}
478→              </button>
479→            )}
480→          </div>
481→        </form>
482→      </>
483→    );
484→  }
485→
486→  function renderLoading() {
487→    return (
488→      <div aria-live="polite" aria-busy="true" style={{ padding: "2rem 0" }}>
489→        <p style={{ color: "#555", fontSize: "1rem" }}>
490→          <LoadingSpinner />
491→          {STRINGS.generatingMessage}
492→        </p>
493→        <style>{"@keyframes spin { to { transform: rotate(360deg); } }"}</style>
494→      </div>
495→    );
496→  }
497→
498→  function renderPreview() {
499→    return (
500→      <>
501→        {oldExpectations.length > 0 && (
502→          <div role="note" style={bannerStyle}>
503→            {STRINGS.reintakeBanner}
504→          </div>
505→        )}
506→
507→        {oldExpectations.length > 0 && (
508→          <section
509→            aria-labelledby="current-profile-preview-heading"
510→            style={{ ...sectionCardStyle, marginBottom: "2rem" }}
511→          >
512→            <h2
513→              id="current-profile-preview-heading"
514→              style={{ fontSize: "1rem", fontWeight: 600, marginBottom: "0.75rem" }}
515→            >
516→              {STRINGS.currentProfileTitle}
517→            </h2>
518→            <ol style={{ margin: 0, paddingLeft: "1.25rem" }}>
519→              {oldExpectations.map((exp, i) => (
520→                <li
521→                  key={`${i}-${exp}`}
522→                  style={{ marginBottom: "0.4rem", fontSize: "0.9rem", color: "#333" }}
523→                >
524→                  {exp}
525→                </li>
526→              ))}
527→            </ol>
528→          </section>
529→        )}
530→
531→        <form onSubmit={handleConfirm} noValidate aria-labelledby="preview-heading">
532→          <h1 id="preview-heading" style={headingStyle}>
533→            {oldExpectations.length > 0 ? STRINGS.newPreviewTitle : STRINGS.previewTitle}
534→          </h1>
535→          <p style={{ color: "#555", marginBottom: "1.25rem" }}>{STRINGS.previewSubtitle}</p>
536→
537→          <fieldset style={{ border: "none", padding: 0, margin: "0 0 1.5rem 0" }}>
538→            <legend
539→              style={{
540→                fontWeight: 500,
541→                marginBottom: "0.75rem",
542→                fontSize: "0.95rem",
543→                color: "#111",
544→              }}
545→            >
546→              Job Expectations
547→            </legend>
548→
549→            {expectations.map((exp, index) => (
550→              <div
551→                // biome-ignore lint/suspicious/noArrayIndexKey: editable list uses index as stable key
552→                key={index}
553→                style={{
554→                  display: "flex",
555→                  gap: "0.5rem",
556→                  alignItems: "center",
557→                  marginBottom: "0.6rem",
558→                }}
559→              >
560→                <label
561→                  htmlFor={`expectation-${index}`}
562→                  style={{ ...labelStyle, margin: 0, whiteSpace: "nowrap" }}
563→                >
564→                  {STRINGS.expectationLabel(index)}
565→                </label>
566→                <input
567→                  id={`expectation-${index}`}
568→                  type="text"
569→                  value={exp}
570→                  onChange={(e) => handleExpectationChange(index, e.target.value)}
571→                  aria-required="true"
572→                  aria-label={STRINGS.expectationLabel(index)}
573→                  style={{
574→                    ...expectationInputStyle,
575→                    borderColor: exp.trim().length === 0 ? "#b91c1c" : "#ccc",
576→                  }}
577→                />
578→                {expectations.length > 1 && (
579→                  <button
580→                    type="button"
581→                    onClick={() => handleRemoveExpectation(index)}
582→                    aria-label={`${STRINGS.removeExpectation} expectation ${index + 1}`}
583→                    style={dangerButtonStyle}
584→                  >
585→                    {STRINGS.removeExpectation}
586→                  </button>
587→                )}
588→              </div>
589→            ))}
590→
591→            {expectationsCountMessage && (
592→              <div role="alert" aria-live="polite" style={validationMessageStyle}>
593→                {expectationsCountMessage}
594→              </div>
595→            )}
596→          </fieldset>
597→
598→          {expectations.length < MAX_EXPECTATIONS && (
599→            <div style={{ marginBottom: "1.5rem" }}>
600→              <button type="button" onClick={handleAddExpectation} style={secondaryButtonStyle}>
601→                {STRINGS.addExpectation}
602→              </button>
603→            </div>
604→          )}
605→
606→          <div style={{ display: "flex", gap: "0.75rem", flexWrap: "wrap" }}>
607→            <button
608→              type="submit"
609→              disabled={!expectationsValid}
610→              style={{
611→                ...primaryButtonStyle,
612→                opacity: expectationsValid ? 1 : 0.6,
613→                cursor: expectationsValid ? "pointer" : "not-allowed",
614→              }}
615→            >
616→              {STRINGS.confirmButton}
617→            </button>
618→            <button type="button" onClick={handleStartOver} style={secondaryButtonStyle}>
619→              {STRINGS.startOverButton}
620→            </button>
621→          </div>
622→        </form>
623→      </>
624→    );
625→  }
626→
627→  function renderConfirmed() {
628→    return (
629→      <section aria-labelledby="confirmed-heading">
630→        <h1 id="confirmed-heading" style={headingStyle}>
631→          {STRINGS.confirmedTitle}
632→        </h1>
633→        <p style={{ color: "#333", marginBottom: "1.5rem" }}>{STRINGS.confirmedMessage}</p>
634→
635→        {existingProfile && (
636→          <div style={sectionCardStyle}>
637→            <h2
638→              style={{ fontSize: "1rem", fontWeight: 600, marginBottom: "0.75rem", color: "#111" }}
639→            >
640→              {STRINGS.currentProfileTitle}
641→            </h2>
642→            <ol style={{ margin: 0, paddingLeft: "1.25rem" }}>
643→              {existingProfile.jobExpectations.map((exp, i) => (
644→                <li
645→                  key={`${i}-${exp}`}
646→                  style={{ marginBottom: "0.4rem", fontSize: "0.9rem", color: "#333" }}
647→                >
648→                  {exp}
649→                </li>
650→              ))}
651→            </ol>
652→          </div>
653→        )}
654→
655→        <div style={{ display: "flex", gap: "0.75rem", flexWrap: "wrap" }}>
656→          <a
657→            href={`/${tenant}/dashboard`}
658→            style={{
659→              ...primaryButtonStyle,
660→              display: "inline-block",
661→              textDecoration: "none",
662→            }}
663→          >
664→            {STRINGS.dashboardLink}
665→          </a>
666→          <button type="button" onClick={handleUpdateProfile} style={secondaryButtonStyle}>
667→            {STRINGS.updateProfileButton}
668→          </button>
669→        </div>
670→      </section>
671→    );
672→  }
673→
674→  function renderError() {
675→    return (
676→      <section aria-labelledby="error-heading" aria-live="assertive">
677→        <h1 id="error-heading" style={{ ...headingStyle, color: "#b91c1c" }}>
678→          {STRINGS.errorTitle}
679→        </h1>
680→        <p style={{ color: "#333", marginBottom: "1.5rem" }}>{error}</p>
681→        <button type="button" onClick={handleRetry} style={primaryButtonStyle}>
682→          {STRINGS.retryButton}
683→        </button>
684→      </section>
685→    );
686→  }
687→
688→  // -------------------------------------------------------------------------
689→  // Main render
690→  // -------------------------------------------------------------------------
691→
692→  return (
693→    <main style={containerStyle}>
