27→export function resolveModel(tenant: Tenant): LanguageModel {
28→  const aiConfig = tenant.settings.ai ?? {};
29→  const provider = aiConfig.provider ?? "anthropic";
30→  const modelId = aiConfig.model ?? "claude-sonnet-4-20250514";
31→  const gatewayUrl = aiConfig.gatewayUrl ?? process.env.AI_GATEWAY_URL;
32→
33→  switch (provider) {
34→    case "anthropic": {
35→      if (!process.env.ANTHROPIC_API_KEY) {
36→        throw new Error(
37→          "ANTHROPIC_API_KEY environment variable is required for Anthropic provider",
38→        );
39→      }
40→      const anthropic = createAnthropic({
41→        apiKey: process.env.ANTHROPIC_API_KEY,
42→        ...(gatewayUrl ? { baseURL: gatewayUrl } : {}),
43→      });
44→      return anthropic(modelId);
45→    }
46→    case "openai": {
47→      if (!process.env.OPENAI_API_KEY) {
48→        throw new Error("OPENAI_API_KEY environment variable is required for OpenAI provider");
49→      }
50→      const openai = createOpenAI({
51→        apiKey: process.env.OPENAI_API_KEY,
52→        ...(gatewayUrl ? { baseURL: gatewayUrl } : {}),
53→      });
54→      return openai(modelId);
55→    }
56→    case "azure-openai": {
57→      if (!process.env.AZURE_OPENAI_API_KEY) {
58→        throw new Error(
59→          "AZURE_OPENAI_API_KEY environment variable is required for Azure OpenAI provider",
60→        );
61→      }
62→      const azure = createAzure({
63→        apiKey: process.env.AZURE_OPENAI_API_KEY,
64→        ...(gatewayUrl ? { baseURL: gatewayUrl } : {}),
65→      });
66→      return azure(modelId);
67→    }
68→    default: {
69→      const _exhaustive: never = provider;
70→      throw new Error(`Unsupported AI provider: ${_exhaustive}`);
71→    }
72→  }
73→}
